<?php
namespace App\Http\Controllers\Tenant;use App\Http\Controllers\Controller;use App\Models\TaskCategory;use App\Support\CurrentWorkspace;use Illuminate\Http\Request;
class TaskCategoryController extends Controller{use Concerns;public function index(){return view('tenant.task-categories.index',['categories'=>TaskCategory::latest()->paginate(20)]);}public function store(Request $r,CurrentWorkspace $cw){$this->requirePerm('tenant.tasks.create');$w=$this->ws($cw);$d=$r->validate(['name'=>'required|string|max:255','description'=>'nullable|string','color'=>'nullable|string|max:30','proof_required'=>'boolean','approval_required'=>'boolean','is_active'=>'boolean']);TaskCategory::create($d+['workspace_id'=>$w->id,'proof_required'=>$r->boolean('proof_required'),'approval_required'=>$r->boolean('approval_required'),'is_active'=>$r->boolean('is_active',true)]);return back()->with('status','Category created.');}}
